import base64
import pickle
import json
from datetime import datetime
from typing import Any, Dict, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def process_pubsub_message(event: Dict[str, Any], context: Any) -> None:
    """
    Cloud Function triggered by Pub/Sub to process serialized Python objects.
    
    Args:
        event: The dictionary with data specific to this type of event.
        context: Metadata of triggering event.
    """
    try:
        # Extract and decode the Pub/Sub message
        if 'data' not in event:
            logger.error("No data field in event")
            return
        
        # Decode base64 encoded data
        message_data = base64.b64decode(event['data'])
        
        # Deserialize the Python object using pickle
        task_data = pickle.loads(message_data)
        
        logger.info(f"Processing task: {type(task_data).__name__}")
        
        # Process the deserialized data
        result = process_task(task_data)
        
        # Log success
        logger.info(f"Task processed successfully: {result}")
        
    except Exception as e:
        logger.error(f"Error processing message: {str(e)}", exc_info=True)
        raise


def process_task(task_data: Any) -> Dict[str, Any]:
    """
    Process the deserialized task data.
    
    Args:
        task_data: Deserialized Python object containing task information.
        
    Returns:
        Dictionary containing processing results.
    """
    result = {
        'status': 'success',
        'timestamp': datetime.utcnow().isoformat(),
        'task_type': type(task_data).__name__
    }
    
    # Handle different task types
    if isinstance(task_data, dict):
        result.update(process_dict_task(task_data))
    elif isinstance(task_data, list):
        result.update(process_list_task(task_data))
    elif hasattr(task_data, '__dict__'):
        result.update(process_object_task(task_data))
    else:
        result.update(process_generic_task(task_data))
    
    return result


def process_dict_task(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process dictionary-based tasks."""
    task_type = task_data.get('type', 'unknown')
    
    if task_type == 'batch_job':
        return process_batch_job(task_data)
    elif task_type == 'data_transformation':
        return process_data_transformation(task_data)
    elif task_type == 'aggregation':
        return process_aggregation(task_data)
    else:
        return {'processed_keys': list(task_data.keys()), 'item_count': len(task_data)}


def process_batch_job(job_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process batch job tasks."""
    job_id = job_data.get('job_id', 'unknown')
    items = job_data.get('items', [])
    operation = job_data.get('operation', 'process')
    
    logger.info(f"Processing batch job {job_id} with {len(items)} items")
    
    processed_items = []
    failed_items = []
    
    for item in items:
        try:
            processed_item = execute_operation(item, operation)
            processed_items.append(processed_item)
        except Exception as e:
            logger.error(f"Failed to process item: {str(e)}")
            failed_items.append({'item': item, 'error': str(e)})
    
    return {
        'job_id': job_id,
        'total_items': len(items),
        'processed': len(processed_items),
        'failed': len(failed_items),
        'failed_items': failed_items
    }


def process_data_transformation(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process data transformation tasks."""
    source_data = task_data.get('data', [])
    transformations = task_data.get('transformations', [])
    
    transformed_data = source_data
    
    for transform in transformations:
        transform_type = transform.get('type')
        
        if transform_type == 'filter':
            condition = transform.get('condition')
            transformed_data = [item for item in transformed_data if evaluate_condition(item, condition)]
        elif transform_type == 'map':
            mapping_func = transform.get('function')
            transformed_data = [apply_mapping(item, mapping_func) for item in transformed_data]
        elif transform_type == 'reduce':
            reducer = transform.get('reducer')
            transformed_data = apply_reducer(transformed_data, reducer)
    
    return {
        'transformation_count': len(transformations),
        'output_size': len(transformed_data) if isinstance(transformed_data, list) else 1,
        'result': transformed_data
    }


def process_aggregation(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process aggregation tasks."""
    data = task_data.get('data', [])
    aggregations = task_data.get('aggregations', [])
    
    results = {}
    
    for agg in aggregations:
        agg_type = agg.get('type')
        field = agg.get('field')
        
        if agg_type == 'sum':
            results[f'sum_{field}'] = sum(item.get(field, 0) for item in data)
        elif agg_type == 'avg':
            values = [item.get(field, 0) for item in data]
            results[f'avg_{field}'] = sum(values) / len(values) if values else 0
        elif agg_type == 'count':
            results[f'count_{field}'] = len([item for item in data if field in item])
        elif agg_type == 'min':
            values = [item.get(field, float('inf')) for item in data]
            results[f'min_{field}'] = min(values) if values else None
        elif agg_type == 'max':
            values = [item.get(field, float('-inf')) for item in data]
            results[f'max_{field}'] = max(values) if values else None
    
    return {
        'aggregation_results': results,
        'record_count': len(data)
    }


def process_list_task(task_data: List[Any]) -> Dict[str, Any]:
    """Process list-based tasks."""
    return {
        'item_count': len(task_data),
        'processed_items': [process_item(item) for item in task_data[:100]]
    }


def process_object_task(task_data: Any) -> Dict[str, Any]:
    """Process custom object tasks."""
    attributes = vars(task_data)
    
    if hasattr(task_data, 'execute'):
        result = task_data.execute()
        return {'execution_result': result, 'attributes': attributes}
    
    return {'attributes': attributes}


def process_generic_task(task_data: Any) -> Dict[str, Any]:
    """Process generic tasks."""
    return {
        'data_type': str(type(task_data)),
        'data_repr': repr(task_data)[:200]
    }


def execute_operation(item: Any, operation: str) -> Any:
    """Execute operation on an item."""
    if operation == 'process':
        return {'original': item, 'processed': True, 'timestamp': datetime.utcnow().isoformat()}
    elif operation == 'validate':
        return {'item': item, 'valid': True}
    elif operation == 'transform':
        return {'transformed': item, 'version': 2}
    else:
        return item


def evaluate_condition(item: Any, condition: Dict[str, Any]) -> bool:
    """Evaluate a condition against an item."""
    if not condition:
        return True
    
    field = condition.get('field')
    operator = condition.get('operator', 'eq')
    value = condition.get('value')
    
    if isinstance(item, dict):
        item_value = item.get(field)
    else:
        item_value = getattr(item, field, None)
    
    if operator == 'eq':
        return item_value == value
    elif operator == 'gt':
        return item_value > value
    elif operator == 'lt':
        return item_value < value
    elif operator == 'gte':
        return item_value >= value
    elif operator == 'lte':
        return item_value <= value
    elif operator == 'ne':
        return item_value != value
    
    return True


def apply_mapping(item: Any, mapping_func: Dict[str, Any]) -> Any:
    """Apply mapping function to an item."""
    func_type = mapping_func.get('type')
    
    if func_type == 'multiply':
        field = mapping_func.get('field')
        factor = mapping_func.get('factor', 1)
        if isinstance(item, dict):
            item[field] = item.get(field, 0) * factor
        return item
    elif func_type == 'uppercase':
        field = mapping_func.get('field')
        if isinstance(item, dict) and field in item:
            item[field] = str(item[field]).upper()
        return item
    
    return item


def apply_reducer(data: List[Any], reducer: Dict[str, Any]) -> Any:
    """Apply reducer to data."""
    reducer_type = reducer.get('type')
    
    if reducer_type == 'sum':
        return sum(data)
    elif reducer_type == 'concat':
        return ''.join(str(item) for item in data)
    elif reducer_type == 'merge':
        result = {}
        for item in data:
            if isinstance(item, dict):
                result.update(item)
        return result
    
    return data


def process_item(item: Any) -> Any:
    """Process a single item."""
    if isinstance(item, dict):
        return {k: v for k, v in item.items()}
    elif isinstance(item, (list, tuple)):
        return [process_item(i) for i in item]
    else:
        return item